+        PRESSURE_REGIME_PRESSURED => "Pressured",
+        PRESSURE_REGIME_OVERLOADED => "Overloaded",
+        PRESSURE_REGIME_RECOVERY => "Recovery",
+        _ => "Nominal",
+    }
+}
+
+fn overload_policy_name(tag: u8) -> &'static str {
